mapper.select:
SELECT kc.id, kc.document_id, kd.title as document_title, kc.chunk_index, kc.content, kc.char_count, kc.metadata, 1 - (kc.embedding <=> #{embedding}::vector) as similarity, kc.create_time FROM knowledge_chunk kc INNER JOIN knowledge_document kd ON kc.document_id = kd.id AND kd.deleted = false AND kd.status = 1
AND 1 - (kc.embedding <=> #{embedding}::vector) >= #{similarityThreshold}
ORDER BY kc.embedding <=> #{embedding}::vector LIMIT #{topK}

SELECT kc.id, kc.document_id, kd.title as document_title, kc.chunk_index, kc.content, kc.char_count, kc.metadata, ts_rank_cd(to_tsvector('simple', kc.content), plainto_tsquery('simple', #{keyword})) as similarity, kc.create_time FROM knowledge_chunk kc INNER JOIN knowledge_document kd ON kc.document_id = kd.id AND kd.deleted = false AND kd.status = 1
to_tsvector('simple', kc.content) @@ plainto_tsquery('simple', #{keyword})
ORDER BY ts_rank_cd(to_tsvector('simple', kc.content), plainto_tsquery('simple', #{keyword})) DESC LIMIT #{topK}

mapper.update:
UPDATE knowledge_chunk
SET embedding = #{embedding}::vector
WHERE id = #{id}
